+/// Converts a hex string to a 32-byte array.
+/// Returns `Err` on invalid hex or wrong length; never silently returns zeros.
+pub fn hex_to_bytes32(hex: &str) -> Result<[u8; 32], HexConversionError> {
+    let bytes = hex::decode(hex)
+        .map_err(|e| HexConversionError(format!("invalid hex '{}': {}", hex, e)))?;
+    bytes
+        .try_into()
+        .map_err(|_| HexConversionError(
+            format!("expected 32 bytes, got {} bytes from '{}'", hex.len() / 2, hex)
+        ))
 }

